  logy:{ stage:"s3e", meaning:"study of", pos:["noun"], examples:["bio<u>logy</u>","geo<u>logy</u>","techno<u>logy</u>","zoo<u>logy</u>","psycho<u>logy</u>","anthro<u>pology</u>"] },
