  chrono:{ stage:"s3e", meaning:"time", pos:["noun"], examples:["<u>chrono</u>logy","<u>chrono</u>meter","<u>chrono</u>logical","<u>chrono</u>logy","<u>chrono</u>type","<u>chrono</u>biology"] },
  photo:{ stage:"s3e", meaning:"light", pos:["noun"], examples:["<u>photo</u>graph","<u>photo</u>copy","<u>photo</u>synthesis","<u>photo</u>electric","<u>photo</u>n","<u>photo</u>journalist"] },
  scope:{ stage:"s3e", meaning:"look; view; examine", pos:["noun","verb"], examples:["tele<u>scope</u>","micro<u>scope</u>","peri<u>scope</u>","endo<u>scope</u>","stethoscope","horo<u>scope</u>"] },
  meter:{ stage:"s3e", meaning:"measure", pos:["noun","verb"], examples:["thermo<u>meter</u>","kilo<u>meter</u>","speedo<u>meter</u>","baro<u>meter</u>","alti<u>meter</u>","diame<u>ter</u>"] },
